(function(){"use strict";var data=window.hivepressActionBarFrontendData||{},bar=document.querySelector(".hp-action-bar");if(!bar){return}if(data.safeArea){var meta=document.querySelector('meta[name="viewport"]');if(meta){var content=meta.getAttribute("content")||"";if(content.indexOf("viewport-fit")===-1){meta.setAttribute("content",content?content+",viewport-fit=cover":"viewport-fit=cover")}}}var path=window.location.pathname.replace(/\/+$/,"")||"/";Array.prototype.forEach.call(bar.querySelectorAll(".hp-action-bar__item"),function(item){var href=item.getAttribute("href");if(!href){return}var link=document.createElement("a");link.href=href;if(link.host!==window.location.host){return}var linkPath=link.pathname.replace(/\/+$/,"")||"/";if(linkPath===path){item.classList.add("hp-action-bar__item--active");item.setAttribute("aria-current","page")}})})();
